2670     auto LHS = m_AShr(m_Value(OpL), m_SpecificInt(ShiftWidth));
2671     auto RHS = m_LShr(m_Neg(m_Value(OpR)), m_SpecificInt(ShiftWidth));
2672     auto Signum = m_Or(LHS, RHS);
2673 
2674     return Signum.match(V) && OpL == OpR && Val.match(OpL);
2675   }
